INSERT INTO products (id, category_id, name, description, price, stock, badge, consult_only, sizes) VALUES
  ('vib-huevo-control-remoto', 'juguetes-mujeres', 'Vibrador huevo con control remoto', 'Huevo vibrador rosa con control remoto inalámbrico. Diseño discreto, textura suave, cordón de extracción. Ideal para estimulación interna y externa.', 100000, 10, 'Nuevo', false, '[]'),
  ('private-massager-control-remoto', 'juguetes-mujeres', 'Private Massager — Vibrador con control remoto', 'Vibrador huevo en silicona con control remoto inalámbrico. 18 funciones de vibración, impermeable, silencioso. Recargable por USB. Incluye cable de carga y empaque.', 90000, 10, 'Nuevo', false, '[]'),
  ('vibrador-app-smartphone', 'juguetes-mujeres', 'Vibrador con control por app', 'Huevo vibrador en silicona controlado desde el celular vía app Bluetooth. 9 modos de vibración, impermeable. Modos Classic, Music, Shake y más. Recargable.', 100000, 10, 'Nuevo', false, '[]'),
  ('mini-bullet-vibrator', 'juguetes-mujeres', 'Mini Bullet Vibrator — Vibrador bala', 'Vibrador bala compacto en acabado cromado. 10 modos de vibración, impermeable, silencioso. Recargable por USB. Tamaño mini, ideal para llevar.', 70000, 10, 'Nuevo', false, '[]'),
  ('malawy-029-consolador', 'juguetes-mujeres', 'Consolador Malawy 029', 'Consolador con funda transparente texturizada, núcleo interno y base negra. Modelo Malawy 029. Estimulación intensa, material suave. Incluye empaque.', 60000, 10, 'Nuevo', false, '[]'),
  ('plug-anal-corazon-rosa', 'juguetes-mujeres', 'Plug anal corazón rosa con gema', 'Plug anal rosa perla con base en forma de corazón y gema rosa facetada. Material metálico/acrílico brillante. Diseño elegante para principiantes o uso decorativo.', 45000, 10, 'Nuevo', false, '[]'),
  ('kit-bondage-10-piezas', 'sadomasoquismo', 'Kit bondage 10 piezas', 'Set completo para parejas: esposas ajustables, antifaz, mordaza, flogger, pluma, cuerda, collar con correa, pinzas y conectores. Material negro con herrajes plateados. Ideal para iniciación.', 30000, 10, 'Nuevo', false, '[]'),
  ('set-bondage-anti-back-handcuffs', 'sadomasoquismo', 'Set bondage Anti-Back Handcuffs', 'Arnés de bondage con collar acolchado en piel sintética, esposas para muñecas y correas ajustables. Sujeta las manos a la espalda. Incluye empaque. Role play para parejas.', 45000, 10, 'Nuevo', false, '[]'),
  ('sen-lub-neutro-30ml', 'sen-intimo', 'Lubricante íntimo Neutro 30 ml', 'Hipoalergénico, pH equilibrado. Lubricación suave, duradera y confortable. Compatible con condones y juguetes. Previene resequedad vaginal, reduce fricción, previene irritaciones.', 22000, 10, NULL, false, '[]'),
  ('sen-lub-neutro-1l', 'sen-intimo', 'Lubricante íntimo Neutro 1 L — SEN ÍNTIMO', 'Lubricante íntimo a base de agua, pH balanceado, ideal para uso diario. Lubricación suave y duradera. Compatible con condones y juguetes. Previene resequedad vaginal y reduce fricción. Presentación 1 L. Fábrica del Placer / SEN ÍNTIMO.', 65000, 10, NULL, false, '[]'),
  ('sen-lub-menta-fria-30ml', 'sen-intimo', 'Lubricante íntimo Menta 30 ml — Edición Especial', 'SEN ÍNTIMO Edición Especial, 30 ml. Sensación fría con sabor menta. Seguro con preservativo. A base de agua, sedoso y suave al tacto. Fácil de lavar, no deja residuos ni manchas. Compatible con condones y juguetes. Registro INVIMA 2022DM-0024284.', 25000, 10, NULL, false, '[]'),
  ('sen-lub-sensacion-caliente-30ml', 'sen-intimo', 'Lubricante íntimo Sensación Caliente 30 ml', 'SEN ÍNTIMO. Lubricante íntimo con sensación caliente. A base de agua, compatible con condones y juguetes. Presentación 30 ml. Sabores disponibles.', NULL, 10, NULL, false, '[{"label":"Chocolate","price":25000,"image":"/catalog/sen-lub-sensacion-caliente-30ml-chocolate.webp"},{"label":"Crema de whisky","price":25000,"image":"/catalog/sen-lub-sensacion-caliente-30ml-crema-whisky.webp"},{"label":"Caramelo","price":25000,"image":"/catalog/sen-lub-sensacion-caliente-30ml-caramelo.webp"},{"label":"Café Moka","price":25000,"image":"/catalog/sen-lub-sensacion-caliente-30ml-cafe-moka.webp"}]'),
  ('sen-vibrador-liquido-electrizante-frio-5ml', 'sen-intimo', 'Vibrador líquido Electrizante Frío', 'Gel vibrador líquido con sensación electrizante y fría. Potente, excitante e inolvidable. Aplicar pocas gotas. Contenido 5 ml.', 39000, 10, NULL, false, '[]'),
  ('sen-lub-cum-250ml', 'sen-intimo', 'Lubricante íntimo CUM — SEN ÍNTIMO', 'Lubricante íntimo SEN ÍNTIMO línea CUM. Simula la eyaculación femenina. A base de agua, compatible con condones y juguetes. Presentación 250 ml con dispensador.', 50000, 10, NULL, false, '[]'),
  ('sen-lub-estrechante-30ml', 'sen-intimo', 'Lubricante íntimo Estrechante — SEN ÍNTIMO', 'Lubricante estrechante SEN ÍNTIMO. Tratamiento progresivo que devuelve la seguridad. Sensación de contracción del conducto vaginal para mayor contacto durante la penetración. Aplicar en la entrada vaginal 10 minutos antes de la relación. Presentación 30 ml.', 39000, 10, NULL, false, '[]'),
  ('dsex-hot-oil-30ml', 'lubricantes', 'Hot Oil Dsex shop labs — 30 ml', 'Aceite y lubricante caliente saborizado para masaje. Lubricante comestible con sabor, línea Hot Oil de Dsex shop labs. Presentación 30 ml. Sabores disponibles: Chocolate, Piña colada, Maracuyá, Lechera, Chicle, Salpicón, Mora azul, Frutos rojos y Uva.', NULL, 10, NULL, false, '[{"label":"Chocolate","price":15000},{"label":"Piña colada","price":15000},{"label":"Maracuyá","price":15000},{"label":"Lechera","price":15000},{"label":"Chicle","price":15000},{"label":"Salpicón","price":15000},{"label":"Mora azul","price":15000},{"label":"Frutos rojos","price":15000},{"label":"Uva","price":15000}]'),
  ('retardex-cerotabu', 'retardantes', 'Retardex Cerotabú', 'Retardante 5 g. Prolonga tus momentos de placer y controla tus sensaciones. Ingredientes naturales que relajan y retrasan los impulsos nerviosos.', 8000, 10, NULL, false, '[]'),
  ('rhino-5ml', 'retardantes', 'Rhino 5 ml', 'Spray retardante 5 ml. Nueva presentación, traído directamente desde Egipto. Producto 100% eficaz para prolongar el placer.', 18000, 10, NULL, false, '[]'),
  ('maxman-edicion-especial', 'retardantes', 'Maxman Edición Especial', 'Suplemento ultra-long. Erecciones más potentes y duraderas, mayor resistencia sexual, control de eyaculación precoz y mejor circulación. Sin efecto rebote.', 8000, 10, NULL, false, '[]'),
  ('retardante-rhino-crema', 'retardantes', 'Retardante Rhino (crema)', 'Crema retardante de aplicación tópica. Prolonga el placer y ayuda a controlar la eyaculación. Presentación compacta con estuche.', 12000, 10, NULL, false, '[]'),
  ('rhino-khartit-tubo', 'retardantes', 'Crema Rhino Khartit — tubo', 'Crema retardante en tubo con estuche. Marca Rhino/Khartit, fórmula importada. Prolonga el placer y ayuda a controlar la eyaculación. Presentación tubo + caja.', 18000, 10, NULL, false, '[]'),
  ('dynamo-ultra-black-power-15ml', 'retardantes', 'Dynamo Ultra Black Power — Spray retardante', 'Spray retardante para hombre. Línea Black Power. Prolonga el placer y ayuda a controlar la eyaculación. Presentación 15 ml con estuche. Ref: Ref05040.', 40000, 10, NULL, false, '[]'),
  ('jamaican-stone', 'retardantes', 'Jamaican Stone', 'Retardante natural en piedra tópica. Frotar la piedra con 3 gotas de agua durante 30 segundos hasta obtener un líquido lechoso; aplicar en el surco balano prepucial durante 15 minutos y luego lavar con agua y jabón. Advertencia: no exceder el tiempo ni la cantidad indicada.', 15000, 10, NULL, false, '[]'),
  ('big-penis-honey', 'potenciadores-masculinos', 'Big Penis Honey', 'Estimulante sexual masculino 100% natural. Ginseng, maca, miel y hierbas seleccionadas. Paquete con 12 sobres de 15 g. Tomar 1 sobre diluido en agua 30 min antes.', NULL, 10, NULL, false, '[{"label":"Paquete x12 sobres","price":18000},{"label":"Sobre individual","price":7000}]'),
  ('gold-fly-original', 'potenciadores-femeninos', 'Original GOLD FLY™', 'Afrodisíaco potente en sobres. Mejora el deseo y la sensibilidad, aumenta el placer y la excitación. Extracto natural de animales y plantas.', 12000, 10, NULL, false, '[]'),
  ('firefox-women-series', 'potenciadores-femeninos', 'Firefox Women Series', 'Estimulante sexual femenino en sobres. Línea Women Series. Despierta tu deseo. Bacchus Biotechnology.', 10000, 10, 'Nuevo', false, '[]'),
  ('firefox-women-supplement-5g', 'potenciadores-femeninos', 'Firefox Women Supplement — Sobre 5 g', 'Estimulante femenino en sobre 5 g. Polvo incoloro e inodoro. Bacchus Biotechnology. Aumenta el deseo, excita rápido, mejora la lubricación, efecto multiorgásmico. Compatible con líquidos y alcohol.', 12000, 10, NULL, false, '[]'),
  ('groben-penis-fem', 'potenciadores-femeninos', 'Groben Penis Fem — Potenciador femenino', 'Potenciador femenino en cápsula. Aumenta el apetito sexual, mejora la lubricación y la excitación. Efecto multiorgásmico. Presentación: 1 cápsula. Tomar 1 cápsula 1 hora antes. Compatible con licor.', 10000, 10, NULL, false, '[]'),
  ('groben-penis-gold', 'potenciadores-masculinos', 'Groben Penis Gold', 'Estimulante masculino en sobre/pasta. 100% natural, compatible con licor. Potencializa la erección y retarda la eyaculación. Hasta 6 días como un toro.', 10000, 10, 'Nuevo', false, '[]'),
  ('groben-penis-silver', 'potenciadores-masculinos', 'Groben Penis Silver', 'Estimulante masculino en sobre plateado. Erección consistente, aumenta sensibilidad y apetito sexual, incrementa duración de erección y más confianza sexual. 100% natural, no adictivo. Apto para hipertensión y diabetes (según empaque).', 10000, 10, 'Nuevo', false, '[]'),
  ('groben-penis-maxxx', 'potenciadores-masculinos', 'Groben Penis MAXXX', 'Estimulante sexual masculino en sobre naranja. Efecto prolongado de 4 a 5 días por estimulación. 100% natural, compatible con licor. Potencializa la erección, retarda la eyaculación y promueve engrosamiento. Excelente para diabéticos (según empaque). Hasta 5 días como un rey.', 10000, 10, NULL, false, '[]'),
  ('sexlove-plus-chewing-gum', 'potenciadores-femeninos', 'Sexlove+ Chewing Gum — Chiclet estimulante femenino', 'Chiclet estimulante sexual femenino, sabor frutas. Aumenta la libido y el deseo sexual. Efecto desde 40 minutos, dura aproximadamente 2 horas. Compatible con licor. Se mastica como un chicle normal.', 12000, 10, NULL, false, '[]'),
  ('gummies-viking-cereza-60g', 'lenceria', 'Ropa íntima comestible Gummies Viking — Cereza', 'Lencería comestible en gomas sabor cereza/frutas. Producto divertido para parejas. Peso neto 60 g. Ref: Ref03525.', 35000, 10, NULL, false, '[]'),
  ('cerotabu-adonis-ducha-anal', 'cuidado-intimo', 'Cerotabú Adonis — Ducha anal', 'Ducha anal y vaginal unisex. Silicona médica de alta calidad, libre de ftalatos. Capacidad 220 ml. Desarmable para fácil limpieza. Marca Cerotabú / Roky.', NULL, 10, NULL, false, '[{"label":"Talla S","price":25000},{"label":"Talla M","price":30000},{"label":"Talla L","price":35000}]'),
  ('men-powerup-penis-pump', 'juguetes-hombres', 'Agrandador de pene — Men Powerup', 'Cilindro en ABS para engrosar y alargar el pene. Bomba manual con manguera. Cilindro 220 mm × 65 mm. Marcas M, L y XL en el interior. Ref: RL35BA01-302. Producto +18.', 70000, 10, '+18', false, '[]')
